#include <print>

template <typename... Friends>
class Account {
    friend Friends...; // каждый тип из пакета становится другом класса
public:
    explicit Account(int balance) : balance_(balance) {}
private:
    int balance_;
};

struct Auditor {
    template <typename... Fs>
    static int balance(const Account<Fs...>& a) { return a.balance_; }
};

struct Teller {
    template <typename... Fs>
    static void deposit(Account<Fs...>& a, int amount) { a.balance_ += amount; }
};

int main() {
    Account<Auditor, Teller> acc(100);
    Teller::deposit(acc, 50);
    std::print("{}\n", Auditor::balance(acc));
}

#include <print>

struct Logger {
    template <typename Box>
    static void log(const Box& b) { std::print("value = {}\n", b.peek()); }
};

template <typename... Extra>
class Box {
    friend Logger;       // обычный friend, как и раньше
    friend Extra...;     // пакет: может быть пустым или содержать не-классовые типы
public:
    explicit Box(int v) : value_(v) {}
private:
    int peek() const { return value_; }
    int value_;
};

int main() {
    Box<> empty(1);              // пустой пакет: friend Extra... ничего не добавляет
    Box<int, double> ignored(2); // int, double -- не типы класса, friend для них no-op

    Logger::log(empty);
    Logger::log(ignored);
}

